(function(){"use strict";chrome.runtime.onInstalled.addListener(()=>{console.log("ClipStream: Extension installed"),n()});async function n(){try{const{token:e}=await chrome.identity.getAuthToken({interactive:!0});if(!e)return;const t=await fetch("https://your-project-id.supabase.co/functions/v1/auth/google",{method:"POST",headers:{"Content-Type":"application/json",Authorization:"Bearer your-anon-key"},body:JSON.stringify({token:e})});if(!t.ok)throw new Error("Auth failed");const s=await t.json();await chrome.storage.local.set({session:s}),console.log("ClipStream: Authenticated successfully")}catch(e){console.error("ClipStream: Auth error",e)}}chrome.runtime.onMessage.addListener((e,r,o)=>{if(e.type==="GET_SESSION")return chrome.storage.local.get("session").then(t=>{o(t.session||null)}),!0;if(e.type==="SIGN_OUT")return chrome.storage.local.remove("session").then(()=>{o({success:!0})}),!0})})();
